  function applyServiceTemplate(idx) {
    const tpl = ROOFING_TEMPLATES[idx];
    if (!tpl) return;
    document.getElementById('asvc-name').value = tpl.name;
    document.getElementById('asvc-desc-editor').value = tpl.desc;
    document.getElementById('asvc-cost').value = tpl.cost;
    document.getElementById('asvc-duration').value = tpl.duration;
    // Update unit dropdown
    const unitDd = document.getElementById('asvc-duration-unit');
    if (unitDd) {
      unitDd.dataset.value = tpl.unit;
      unitDd.querySelector('.unit-dd-val').textContent = tpl.unit;
      unitDd.querySelectorAll('.unit-dd-item').forEach(item => {
        item.classList.toggle('selected', item.textContent.trim() === tpl.unit);
      });
    }
    // Highlight active chip
    document.querySelectorAll('.asvc-tpl-chip').forEach((c, i) => c.classList.toggle('active', i === idx));
    updateAddServicePreview();
  }

  function openAddServiceScreen() {
    document.getElementById('services-screen').classList.remove('open');
    document.getElementById('add-service-screen').classList.add('open');
    document.querySelector('.asvc-page-title').textContent = 'Add a new service';
    document.getElementById('asvc-prev-img').src = DEFAULT_THUMB;
    // Reset form
    resetAddServiceForm();
  }
  /* ── Custom unit dropdown (replaces native <select> for Mins/Hours etc.) ── */
  function toggleUnitDd(btn) {
    const menu = btn.nextElementSibling;
    const isOpen = menu.classList.contains('open');
    document.querySelectorAll('.unit-dd-menu.open').forEach(m => m.classList.remove('open'));
    if (!isOpen) menu.classList.add('open');
  }
  function selectUnitDd(item, value) {
    const menu = item.closest('.unit-dd-menu');
    const wrapper = item.closest('.unit-dd');
    wrapper.querySelector('.unit-dd-val').textContent = value;
    wrapper.dataset.value = value;
    menu.querySelectorAll('.unit-dd-item').forEach(i => i.classList.remove('selected'));
    item.classList.add('selected');
    menu.classList.remove('open');
    if (wrapper.dataset.onchange && window[wrapper.dataset.onchange]) {
      window[wrapper.dataset.onchange]();
    }
  }
  document.addEventListener('click', () => {
    document.querySelectorAll('.unit-dd-menu.open').forEach(m => m.classList.remove('open'));
  });

  function toggleSvcDropdown(e, btn) {
    e.stopPropagation();
    const menu = btn.nextElementSibling;
    const isOpen = menu.classList.contains('open');
    document.querySelectorAll('.svc-dropdown.open').forEach(d => d.classList.remove('open'));
    if (!isOpen) menu.classList.add('open');
  }
  document.addEventListener('click', () => {
    document.querySelectorAll('.svc-dropdown.open').forEach(d => d.classList.remove('open'));
  });

  function duplicateService(btn) {
    const card = btn.closest('[id^="svc-card-"]');
    const idx = parseInt(card.id.split('-')[2]);
    const src = services[idx];
    if (!src) return;
    const newSvc = { ...src, name: src.name + ' (Copy)' };
    services.push(newSvc);
    const newIdx = services.length - 1;
    const clone = card.cloneNode(true);
    clone.id = `svc-card-${newIdx}`;
    clone.onclick = () => selectService(newIdx);
    clone.querySelector('.svc2-name').textContent = newSvc.name;
    clone.querySelectorAll('.svc-dropdown').forEach(d => d.classList.remove('open'));
    card.parentNode.insertBefore(clone, card.nextSibling);
    showToast('Service duplicated');
  }

  function deleteService(btn) {
    const card = btn.closest('[id^="svc-card-"]');
    card.remove();
    showToast('Service deleted');
  }

  function closeAddServiceScreen() {
    document.getElementById('add-service-screen').classList.remove('open');
    document.getElementById('services-screen').classList.add('open');
    document.querySelector('.asvc-page-title').textContent = 'Add a new service';
  }
  function resetAddServiceForm() {
    const tpl = ROOFING_TEMPLATES[0]; // Prefill with Roof Inspection defaults
    document.getElementById('asvc-name').value = tpl.name;
    document.getElementById('asvc-desc-editor').value = tpl.desc;
    document.getElementById('asvc-cost').value = tpl.cost;
    document.getElementById('asvc-duration').value = tpl.duration;
    const unitDd = document.getElementById('asvc-duration-unit');
    if (unitDd) {
      unitDd.dataset.value = tpl.unit;
      unitDd.querySelector('.unit-dd-val').textContent = tpl.unit;
      unitDd.querySelectorAll('.unit-dd-item').forEach(item => {
        item.classList.toggle('selected', item.textContent.trim() === tpl.unit);
      });
    }
    updateAddServicePreview();
  }
  function updateAddServicePreview() {
    const name = document.getElementById('asvc-name').value || 'Service name here';
    const desc = document.getElementById('asvc-desc-editor').value || 'Add a description to help customers understand this service.';
    const cost = document.getElementById('asvc-cost').value.trim();
    document.getElementById('asvc-prev-name').textContent = name;
    document.getElementById('asvc-prev-desc').textContent = desc;
    const costEl = document.getElementById('asvc-prev-cost');
    if (costEl) {
      costEl.textContent = cost ? 'Starting at ' + cost : '';
      costEl.style.display = cost ? 'block' : 'none';
    }
  }
  function toggleAsvcSection(toggleId, sectionId) {
    const t = document.getElementById(toggleId);
    const s = document.getElementById(sectionId);
    t.classList.toggle('on');
    s.style.display = t.classList.contains('on') ? 'block' : 'none';
  }
  /* ── Appointment Spacing ── */
  function selectSpacing(type) {
    ['none','fixed','smart'].forEach(t => {
      const opt = document.getElementById(`spacing-opt-${t}`);
      const sub = document.getElementById(`spacing-sub-${t}`);
      const radio = opt?.querySelector('input[type="radio"]');
      if (opt) opt.classList.toggle('selected', t === type);
      if (radio) radio.checked = (t === type);
      if (sub) sub.classList.toggle('visible', t === type);
    });
  }

  function saveAddService() {
    const name = document.getElementById('asvc-name').value.trim();
    if (!name) { showToast('Please enter an option name'); return; }
    const desc = document.getElementById('asvc-desc-editor').value ? document.getElementById('asvc-desc-editor').value.trim() : '';
    const newSvc = { name, desc: desc || 'Service description', price: '—', unit: '/sq', monthly: '', badge: '', img: DEFAULT_THUMB };
    services.push(newSvc);
    const idx = services.length - 1;
    const list = document.getElementById('svc-list');
    const card = document.createElement('div');
    card.className = 'svc2-card'; card.id = `svc-card-${idx}`;
    card.onclick = () => selectService(idx);
    card.innerHTML = `
      <div class="svc2-thumb">
        <img src="${DEFAULT_THUMB}" style="width:100%;height:100%;object-fit:cover;" />
      </div>
      <div class="svc2-info">
        <p class="svc2-name">${name}</p>
        <p class="svc2-desc">${desc || ''}</p>
      </div>
      <div style="display:flex;align-items:center;gap:8px;flex-shrink:0;">
        <div class="svc-toggle on" onclick="event.stopPropagation();this.classList.toggle('on')"></div>
        <button class="svc2-icon-btn" onclick="event.stopPropagation();openEditServiceScreen(${idx})">
          <svg fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/></svg>
        </button>
        <div style="position:relative;">
          <button class="svc2-more" onclick="event.stopPropagation();toggleSvcDropdown(event,this)">
            <svg fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2"><circle cx="12" cy="5" r="1"/><circle cx="12" cy="12" r="1"/><circle cx="12" cy="19" r="1"/></svg>
          </button>
          <div class="svc-dropdown">
            <div class="dropdown-section">
              <button class="dropdown-item" onclick="event.stopPropagation();duplicateService(this)">
                <svg fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2"><rect x="9" y="9" width="13" height="13" rx="2"/><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"/></svg>
                Duplicate
              </button>
              <button class="dropdown-item danger" onclick="event.stopPropagation();deleteService(this)">
                <svg fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2"><polyline points="3 6 5 6 21 6"/><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a1 1 0 0 1 1-1h4a1 1 0 0 1 1 1v2"/></svg>
                Delete
              </button>
            </div>
          </div>
        </div>
      </div>`;
    list.appendChild(card);
    closeAddServiceScreen();
    // Highlight the new card and update preview without re-opening the edit screen
    selectedSvcIdx = idx;
    document.querySelectorAll('[id^="svc-card-"]').forEach((el, i) => el.classList.toggle('selected', i === idx));
    renderServicePreview();
    showToast('Service option added!');
  }

  // Rich text editor slash command menu
  let slashMenuVisible = false;
  function handleEditorInput(e) {
    updateAddServicePreview();
    const editor = document.getElementById('asvc-desc-editor');
    const text = editor.innerText;
    const menu = document.getElementById('asvc-slash-menu');
    if (text.endsWith('/')) {
      // show command menu
      menu.style.display = 'block';
      slashMenuVisible = true;
    } else {
      menu.style.display = 'none';
      slashMenuVisible = false;
    }
  }
  function insertFormat(tag, label) {
    const editor = document.getElementById('asvc-desc-editor');
    // Remove trailing slash
    const sel = window.getSelection();
    editor.focus();
    document.getElementById('asvc-slash-menu').style.display = 'none';
    slashMenuVisible = false;
    // simple: just clear and start fresh with placeholder context
    const text = editor.innerText.replace(/\/$/, '');
    editor.innerHTML = text;
    // move cursor to end
    const range = document.createRange();
    range.selectNodeContents(editor);
    range.collapse(false);
    sel.removeAllRanges();
    sel.addRange(range);
  }

// Collapse helpers for add-service sections
  /* ── Slot Duration pills ── */
  function selectDuration(btn, val) {
    document.querySelectorAll('.ie-dur-pill').forEach(p => p.classList.remove('active'));
    btn.classList.add('active');
    document.getElementById('asvc-duration').value = val;
  }
  function onCustomDuration(input) {
    document.querySelectorAll('.ie-dur-pill').forEach(p => {
      p.classList.toggle('active', parseInt(p.textContent) === parseInt(input.value));
    });
  }

  /* ── Skills multi-select ── */
  const selectedSkills = new Set();
  function toggleSkillsDropdown(e) {
    e.stopPropagation();
    const dd = document.getElementById('skills-dropdown');
    const ms = document.getElementById('skills-multiselect');
    const open = dd.style.display === 'flex';
    dd.style.display = open ? 'none' : 'flex';
    ms.classList.toggle('open', !open);
  }
  function toggleSkill(checkbox) {
    const val = checkbox.value;
    if (checkbox.checked) selectedSkills.add(val);
    else selectedSkills.delete(val);
    renderSkillChips();
  }
  function removeSkill(val) {
    selectedSkills.delete(val);
    const cb = document.querySelector(`#skills-dropdown input[value="${val}"]`);
    if (cb) cb.checked = false;
    renderSkillChips();
  }
  function renderSkillChips() {
    const wrap = document.getElementById('skills-chips');
    if (!wrap) return;
    // Clear chips but keep placeholder span in place
    Array.from(wrap.querySelectorAll('.ie-chip')).forEach(c => c.remove());
    const placeholder = document.getElementById('skills-placeholder');
    if (selectedSkills.size === 0) {
      if (placeholder) placeholder.style.display = '';
    } else {
      if (placeholder) placeholder.style.display = 'none';
      selectedSkills.forEach(skill => {
        const chip = document.createElement('span');
        chip.className = 'ie-chip';
        chip.innerHTML = `${skill}<button class="ie-chip-x" onclick="event.stopPropagation();removeSkill('${skill}')"><svg fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2.5" width="11" height="11"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg></button>`;
        wrap.appendChild(chip);
      });
    }
  }
  // Close dropdowns when clicking outside
  document.addEventListener('click', (e) => {
    const dd = document.getElementById('skills-dropdown');
    const ms = document.getElementById('skills-multiselect');
    if (dd && ms && !ms.contains(e.target) && !dd.contains(e.target)) {
      dd.style.display = 'none'; ms.classList.remove('open');
    }
    const add = document.getElementById('assign-dropdown');
    const ams = document.getElementById('assign-multiselect');
    if (add && ams && !ams.contains(e.target) && !add.contains(e.target)) {
      add.style.display = 'none'; ams.classList.remove('open');
    }
    const assignDd = document.getElementById('assign-dd');
    const assignTrigger = document.getElementById('assign-trigger');
    if (assignDd && assignDd.style.display !== 'none' && e.target.isConnected &&
        !assignDd.contains(e.target) && !assignTrigger.contains(e.target)) {
      closeAssignDropdown();
    }
  });

